test("parseDevServerArgs refuses non-loopback hosts by default", () => {
  assert.throws(
    () => parseDevServerArgs(["--host", "0.0.0.0"], {}),
    /Refusing to bind non-loopback host/,
  );

  const options = parseDevServerArgs(["--host", "0.0.0.0"], {
    CODEX_APP_PORT_ALLOW_NON_LOOPBACK: "1",
  });
  assert.equal(options.host, "0.0.0.0");
});

test("parseDevServerArgs accepts only configured workspace allowlist entries", () => {
  const options = parseDevServerArgs(
    ["--workspace", "/tmp/cli-workspace", "--project-root", "/tmp/cli-projects"],
    {
    CODEX_APP_PORT_WORKSPACES: "/tmp/env-one:/tmp/env-two",
      CODEX_APP_PORT_PROJECT_ROOTS: "/tmp/env-projects",
    },
  );

  assert.deepEqual(options.workspaceInputs, [
    "/tmp/env-one",
    "/tmp/env-two",
    "/tmp/cli-workspace",
  ]);
  assert.deepEqual(options.projectRootInputs, ["/tmp/env-projects", "/tmp/cli-projects"]);
  assert.equal(options.approvalAuditLogPath, null);
  assert.equal(options.actionAuditLogPath, null);

  const auditOptions = parseDevServerArgs(
    ["--approval-audit-log", "/tmp/approval.jsonl", "--action-audit-log", "/tmp/actions.jsonl"],
    {},
  );
  assert.equal(auditOptions.approvalAuditLogPath, "/tmp/approval.jsonl");
  assert.equal(auditOptions.actionAuditLogPath, "/tmp/actions.jsonl");
});

test("dev server discovers opt-in Git project roots without symlinks", async () => {
  const root = await mkdtemp(join(tmpdir(), "codex-project-root-"));
  try {
    await mkdir(join(root, "alpha", ".git"), { recursive: true });
    await mkdir(join(root, "beta"), { recursive: true });
    await writeFile(join(root, "beta", ".git"), "gitdir: ../.git/worktrees/beta\n", "utf8");
    await mkdir(join(root, "not-a-repo"), { recursive: true });
    await mkdir(join(root, ".hidden", ".git"), { recursive: true });
    await symlink(join(root, "alpha"), join(root, "linked-alpha"));

    const projects = discoverProjectWorkspaces({
      cwd: "/tmp/codex-app-port-test",
      projectRootInputs: [root],
    });
    assert.deepEqual(projects.sort(), [join(root, "alpha"), join(root, "beta")].sort());

    const workspaces = createWorkspaceAllowlist({
      cwd: "/tmp/codex-app-port-test",
      projectRootInputs: [root],
    });
    assert.deepEqual(
      workspaces.map((workspace) => workspace.label),
      ["codex-app-port-test", "alpha", "beta"],
    );
  } finally {
    await rm(root, { recursive: true, force: true });
  }
});

test("dev server exposes discovered projects as opaque workspace ids", async () => {
  const root = await mkdtemp(join(tmpdir(), "codex-project-root-"));
  await mkdir(join(root, "project-one", ".git"), { recursive: true });
  const { server, url } = await startTestServer({
    projectRootInputs: [root],
  });
  try {
    const response = await fetch(`${url}/api/workspaces`, {
      headers: apiHeaders(server),
    });
    assert.equal(response.status, 200);
    const payload = await response.json();
    assert.equal(payload.workspaces.length, 2);
    assert.deepEqual(payload.workspaces[1], {
      id: "workspace-2",
      label: "project-one",
      isDefault: false,
    });
    assert.equal(JSON.stringify(payload).includes(root), false);
  } finally {
    await closeServer(server);
    await rm(root, { recursive: true, force: true });
  }
});

