test("dev server rejects browser POST field policy violations before side effects", async () => {
  let probeCalled = false;
  const { server, url } = await startTestServer({
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
    gitWorktreeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });
  const cases = [
    {
      path: "/api/terminal-command-preflight",
      body: {
        command: "echo\0private",
      },
    },
    {
      path: "/api/mcp-tool-preflight",
      body: {
        server: "safe-server",
        tool: "safe-tool",
        arguments: { payload: "x".repeat(8_100) },
      },
    },
    {
      path: "/api/config-batch-preflight",
      body: {
        edits: `[{"keyPath":"safe","value":"${"x".repeat(8_100)}","mergeStrategy":"replace"}]`,
      },
    },
    {
      path: "/api/action-preflight-confirm",
      body: {
        actionType: "terminal-command-preflight",
        preflightToken: "preflight-1234567890abcdef",
        command: "echo\0private",
      },
    },
  ];

  try {
    for (const testCase of cases) {
      const response = await fetch(`${url}${testCase.path}`, {
        method: "POST",
        headers: jsonHeaders(server),
        body: JSON.stringify(testCase.body),
      });
      assert.equal(response.status, 400, testCase.path);
      const text = await response.text();
      assert.equal(text.includes("private"), false, testCase.path);
      assert.equal(text.includes("payload"), false, testCase.path);
      assert.equal(text.includes("command"), false, testCase.path);
      assert.equal(text.includes("arguments"), false, testCase.path);
    }
    assert.equal(probeCalled, false);
  } finally {
    await closeServer(server);
  }
});

test("dev server exposes sanitized read-only status API", async () => {
  const calls = [];
  const { server, url } = await startTestServer({
    probeFn: async (options) => {
      calls.push(options);
      return {
        ok: true,
        generatedAt: "2026-05-16T00:00:00.000Z",
        transport: "stdio-jsonl",
        protocol: "json-rpc-2.0-without-jsonrpc-field",
        codex: { bin: options.codexBin },
        initialize: {
          userAgent: "mock/0.0.0",
          codexHome: "/tmp/codex-home",
          platformFamily: "unix",
          platformOs: "linux",
        },
        probes: {
          config: {
            model: "gpt-test",
            modelProvider: null,
            approvalPolicy: "on-request",
            sandboxMode: "workspace-write",
            profile: null,
            profilesCount: 0,
            originsCount: 0,
            layersIncluded: false,
          },
          threads: {
            count: 1,
            hasNextCursor: false,
            hasBackwardsCursor: false,
            archived: false,
            items: [
              {
                idSuffix: "12345678",
                archived: false,
                hasName: true,
                hasPreview: true,
                status: { type: "notLoaded" },
                source: "cli",
                modelProvider: "openai",
                createdAt: 1,
                updatedAt: 2,
                cwdBasename: "repo",
                hasGitInfo: false,
              },
            ],
          },
          archivedThreads: {
            count: 1,
            hasNextCursor: false,
            hasBackwardsCursor: false,
            archived: true,
            items: [
              {
                idSuffix: "87654321",
                archived: true,
                hasName: true,
                hasPreview: true,
                status: "completed",
                source: "cli",
                modelProvider: "openai",
                createdAt: 3,
                updatedAt: 4,
                cwdBasename: "archived-repo",
                hasGitInfo: false,
                name: "Sensitive archived name",
                preview: "Sensitive archived preview",
                cwd: "/tmp/codex-app-port-test/private",
              },
            ],
          },
        },
        notifications: {},
      };
    },
  });

  try {
    const response = await fetch(`${url}/api/status`, {
      headers: apiHeaders(server),
    });
    assert.equal(response.status, 200);
    const payload = await response.json();
    const serialized = JSON.stringify(payload);
    assert.equal(payload.ok, true);
    assert.equal(payload.initialize.platformOs, "linux");
    assert.deepEqual(payload.workspace, {
      id: "default",
      label: "codex-app-port-test",
      isDefault: true,
    });
    assert.equal(payload.localCapabilities.agentTurnProbeEnabled, false);
    assert.equal(payload.localCapabilities.turnStartEnabled, false);
    assert.equal(calls[0].readonly, true);
    assert.equal(calls[0].cwd, "/tmp/codex-app-port-test");
    assert.equal(calls[0].threadLimit, 8);
    assert.equal(serialized.includes("preview body"), false);
    assert.equal(serialized.includes("Sensitive archived"), false);
    assert.equal(serialized.includes("codexHome"), false);
    assert.equal(serialized.includes("userAgent"), false);
    assert.equal(serialized.includes("/tmp/codex-home"), false);
    assert.equal(serialized.includes("/tmp/codex-app-port-test"), false);
    assert.equal(Object.hasOwn(payload, "codex"), false);
    assert.equal(Object.hasOwn(payload.probes.threads.items[0], "id"), false);
    assert.equal(Object.hasOwn(payload.probes.threads.items[0], "name"), false);
    assert.equal(Object.hasOwn(payload.probes.threads.items[0], "preview"), false);
    assert.equal(payload.probes.archivedThreads.archived, true);
    assert.equal(payload.probes.archivedThreads.items[0].archived, true);
    assert.equal(payload.probes.archivedThreads.items[0].cwdBasename, "archived-repo");
    assert.equal(Object.hasOwn(payload.probes.archivedThreads.items[0], "name"), false);
    assert.equal(Object.hasOwn(payload.probes.archivedThreads.items[0], "preview"), false);
  } finally {
    await closeServer(server);
  }
});

