    assert.equal(payload.threadSearch.items[0].idSuffix, "abcd1234");
    assert.equal(payload.threadSearch.items[0].hasSnippet, true);
    assert.equal(payload.threadSearch.items[0].hasName, true);
    assert.equal(payload.threadSearch.items[0].hasPreview, true);
    assert.equal(payload.threadSearch.searchTermReturned, false);
    assert.equal(payload.threadSearch.snippetsReturned, false);
    assert.equal(payload.threadSearch.namesReturned, false);
    assert.equal(payload.threadSearch.previewsReturned, false);
    assert.equal(payload.threadSearch.fullIdsReturned, false);
    assert.equal(payload.threadSearch.pathsReturned, false);
    assert.equal(payload.threadSearch.cursorsReturned, false);
