test("dev server exposes sanitized read-only git worktree metadata", async () => {
  let probeCalled = false;
  const workspace = await mkdtemp(join(tmpdir(), "codex-app-port-git-api-"));
  await mkdir(join(workspace, ".git", "worktrees", "linked-one"), { recursive: true });
  await mkdir(join(workspace, ".git", "refs", "heads", "feature"), { recursive: true });
  await writeFile(join(workspace, ".git", "HEAD"), "ref: refs/heads/feature/api\n", "utf8");
  await writeFile(
    join(workspace, ".git", "refs", "heads", "feature", "api"),
    "aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa\n",
    "utf8",
  );
  await writeFile(
    join(workspace, ".git", "packed-refs"),
    "bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb refs/heads/release/api\n",
    "utf8",
  );
  await writeFile(
    join(workspace, ".git", "worktrees", "linked-one", "HEAD"),
    "cccccccccccccccccccccccccccccccccccccccc\n",
    "utf8",
  );
  await writeFile(
    join(workspace, ".git", "config"),
    '[remote "origin"]\n\turl = git@example.test:private/repo.git\n',
    "utf8",
  );
  await writeFile(join(workspace, "clean.txt"), "clean", "utf8");
  await writeFile(join(workspace, "modified.txt"), "changed", "utf8");
  await writeFile(join(workspace, "untracked.txt"), "local", "utf8");
  await writeGitIndex(join(workspace, ".git", "index"), [
    await indexEntry(workspace, "clean.txt"),
    { path: "modified.txt", size: 1, mtimeSeconds: 1 },
    { path: "missing.txt", size: 7, mtimeSeconds: 1 },
  ]);

  const { server, url } = await startTestServer({
    cwd: workspace,
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });

  try {
    const postResponse = await fetch(`${url}/api/git-worktree`, {
      method: "POST",
      headers: apiHeaders(server),
    });
    assert.equal(postResponse.status, 405);

    const response = await fetch(`${url}/api/git-worktree`, {
      headers: apiHeaders(server),
    });
    assert.equal(response.status, 200);
    const payload = await response.json();
    const serialized = JSON.stringify(payload);
    assert.equal(payload.ok, true);
    assert.equal(payload.git.isRepository, true);
    assert.equal(payload.git.gitMetadataType, "directory");
    assert.equal(payload.git.headKind, "branch");
    assert.equal(payload.git.branch, "feature/api");
    assert.equal(payload.git.remoteCount, 1);
    assert.equal(payload.git.localBranchCount, 2);
    assert.equal(payload.git.returnedBranchCount, 2);
    assert.deepEqual(
      payload.git.branches.find((branch) => branch.name === "feature/api"),
      { name: "feature/api", current: true, commitShort: "aaaaaaaaaaaa" },
    );
    assert.equal(payload.git.linkedWorktreeCount, 1);
    assert.equal(payload.git.returnedLinkedWorktreeCount, 1);
    assert.deepEqual(payload.git.linkedWorktrees[0], {
      label: "linked-one",
      headKind: "detached",
      branch: null,
      commitShort: "cccccccccccc",
    });
    assert.equal(payload.git.statusAvailable, true);
    assert.equal(payload.git.statusMode, "index-mtime-size");
    assert.equal(payload.git.trackedFileCount, 3);
    assert.equal(payload.git.checkedTrackedFileCount, 2);
    assert.equal(payload.git.modifiedTrackedCount, 1);
    assert.equal(payload.git.missingTrackedCount, 1);
    assert.equal(payload.git.untrackedTopLevelCount, 1);
    assert.deepEqual(payload.git.branchSwitchSafety, {
      hookFileCount: 0,
      filterConfigCount: 0,
      attributesFileCount: 0,
      configExecutionCount: 0,
      hooksPresent: false,
      filtersPresent: false,
      attributesPresent: false,
      configExecutionPresent: false,
      riskPresent: false,
      scanTruncated: false,
    });
    assert.equal(payload.git.branchSwitchAvailable, false);
    assert.equal(payload.git.commitActionsAvailable, false);
    assert.equal(probeCalled, false);
    assert.equal(serialized.includes(workspace), false);
    assert.equal(serialized.includes("git@example.test"), false);
    assert.equal(serialized.includes("private/repo"), false);
    assert.equal(Object.hasOwn(payload.workspace, "cwd"), false);

    const rejected = await fetch(`${url}/api/git-worktree?workspace=${encodeURIComponent(workspace)}`, {
      headers: apiHeaders(server),
    });
    assert.equal(rejected.status, 404);
  } finally {
    await closeServer(server);
    await rm(workspace, { recursive: true, force: true });
  }
});

