test("dev server switches Git branches only behind explicit opt-in and preflight token", async () => {
  const git = {
    isRepository: true,
    gitMetadataType: "directory",
    isLinkedWorktree: false,
    followsLinkedGitDir: false,
    headKind: "branch",
    branch: "feature/api",
    commitShort: "aaaaaaaaaaaa",
    hasRemotes: true,
    remoteCount: 1,
    localBranchCount: 2,
    returnedBranchCount: 2,
    branches: [
      { name: "feature/api", current: true, commitShort: "aaaaaaaaaaaa" },
      { name: "release/api", current: false, commitShort: "bbbbbbbbbbbb" },
    ],
    linkedWorktreeCount: 0,
    returnedLinkedWorktreeCount: 0,
    linkedWorktrees: [],
    statusAvailable: true,
    statusMode: "index-mtime-size",
    trackedFileCount: 1,
    checkedTrackedFileCount: 1,
    modifiedTrackedCount: 0,
    missingTrackedCount: 0,
    untrackedTopLevelCount: 0,
    statusTruncated: false,
    branchSwitchSafety: {
      hookFileCount: 0,
      filterConfigCount: 0,
      attributesFileCount: 0,
      configExecutionCount: 0,
      hooksPresent: false,
      filtersPresent: false,
      attributesPresent: false,
      configExecutionPresent: false,
      riskPresent: false,
      scanTruncated: false,
      warnings: [],
    },
    branchSwitchAvailable: false,
    commitActionsAvailable: false,
    warnings: [],
  };
  let switchCalls = 0;
  const disabled = await startTestServer({
    cwd: "/tmp/default-workspace",
    gitWorktreeFn: async () => git,
    gitBranchSwitchFn: async () => {
      switchCalls += 1;
      return {};
    },
  });

  try {
    const preflight = await fetch(`${disabled.url}/api/git-branch-preflight`, {
      method: "POST",
      headers: jsonHeaders(disabled.server),
      body: JSON.stringify({
        branch: "release/api",
      }),
    });
    assert.equal(preflight.status, 200);
    const preflightPayload = await preflight.json();
    const blocked = await fetch(`${disabled.url}/api/git-branch-switch`, {
      method: "POST",
      headers: jsonHeaders(disabled.server),
      body: JSON.stringify({
        branch: "release/api",
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    assert.equal(blocked.status, 403);
    const blockedPayload = await blocked.json();
    assert.equal(blockedPayload.action.reason, "git-branch-switch-disabled");
    assert.equal(blockedPayload.action.filesystemWrites, false);
    assert.equal(switchCalls, 0);
  } finally {
    await closeServer(disabled.server);
  }

  const enabledCalls = [];
  const enabled = await startTestServer({
    cwd: "/tmp/default-workspace",
    gitWorktreeFn: async () => git,
    gitBranchSwitchEnabled: true,
    gitBranchSwitchFn: async (options) => {
      enabledCalls.push(options);
      return {
        ok: true,
        generatedAt: "2026-05-16T00:00:00.000Z",
        action: {
          type: "git-branch-switch",
          execution: "completed",
          branchSwitchExecuted: true,
          gitSubprocess: true,
          filesystemWrites: true,
          appServerTouched: false,
          reason: null,
        },
        target: {
          branch: "release/api",
          current: false,
          commitShort: "bbbbbbbbbbbb",
        },
        before: {
          branch: "feature/api",
          headKind: "branch",
          commitShort: "aaaaaaaaaaaa",
        },
        after: {
          branch: "release/api",
          headKind: "branch",
          commitShort: "bbbbbbbbbbbb",
        },
        status: {
          before: {
            statusAvailable: true,
            changedCount: 0,
            modifiedTrackedCount: 0,
            missingTrackedCount: 0,
            untrackedTopLevelCount: 0,
            statusTruncated: false,
          },
          after: {
            statusAvailable: true,
            changedCount: 0,
            modifiedTrackedCount: 0,
            missingTrackedCount: 0,
            untrackedTopLevelCount: 0,
            statusTruncated: false,
          },
        },
        safety: git.branchSwitchSafety,
        subprocess: {
          invoked: true,
          command: "git switch",
          exitCode: 0,
        },
      };
    },
  });

  try {
    const missingPreflight = await fetch(`${enabled.url}/api/git-branch-switch`, {
      method: "POST",
      headers: jsonHeaders(enabled.server),
      body: JSON.stringify({
        branch: "release/api",
      }),
    });
    assert.equal(missingPreflight.status, 400);
    assert.equal(enabledCalls.length, 0);

    const preflight = await fetch(`${enabled.url}/api/git-branch-preflight`, {
      method: "POST",
      headers: jsonHeaders(enabled.server),
      body: JSON.stringify({
        branch: "release/api",
      }),
    });
    assert.equal(preflight.status, 200);
    const preflightPayload = await preflight.json();
    assert.equal(preflightPayload.policy.executionGateEnabled, true);

    const response = await fetch(`${enabled.url}/api/git-branch-switch`, {
      method: "POST",
      headers: jsonHeaders(enabled.server),
      body: JSON.stringify({
        branch: "release/api",
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    assert.equal(response.status, 200);
    const payload = await response.json();
    const serialized = JSON.stringify(payload);
    assert.equal(payload.ok, true);
    assert.equal(payload.action.type, "git-branch-switch");
    assert.equal(payload.action.execution, "completed");
    assert.equal(payload.action.branchSwitchExecuted, true);
    assert.equal(payload.action.gitSubprocess, true);
    assert.equal(payload.action.filesystemWrites, true);
    assert.equal(payload.appServer.touched, false);
    assert.equal(payload.preflight.tokenConsumed, true);
    assert.equal(payload.preflight.tokenReturned, false);
    assert.equal(payload.target.branch, "release/api");
    assert.equal(payload.before.branch, "feature/api");
    assert.equal(payload.after.branch, "release/api");
    assert.equal(payload.status.before.changedCount, 0);
    assert.equal(payload.status.after.changedCount, 0);
    assert.equal(payload.subprocess.command, "git switch");
    assert.equal(payload.subprocess.argvReturned, false);
    assert.equal(payload.subprocess.stdoutReturned, false);
    assert.equal(payload.subprocess.stderrReturned, false);
    assert.equal(payload.policy.implemented, true);
    assert.equal(enabledCalls.length, 1);
    assert.equal(enabledCalls[0].workspace.cwd, "/tmp/default-workspace");
    assert.equal(enabledCalls[0].branch, "release/api");
    assert.equal(serialized.includes(preflightPayload.preflight.token), false);
    assert.equal(serialized.includes("/tmp/default-workspace"), false);
    assert.equal(serialized.includes("git@example.test"), false);

    const replay = await fetch(`${enabled.url}/api/git-branch-switch`, {
      method: "POST",
      headers: jsonHeaders(enabled.server),
      body: JSON.stringify({
        branch: "release/api",
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    assert.equal(replay.status, 409);
    assert.equal(enabledCalls.length, 1);
  } finally {
    await closeServer(enabled.server);
  }
});

