test("dev server preflights Git commits without executing Git", async () => {
  let probeCalled = false;
  const workspace = await mkdtemp(join(tmpdir(), "codex-app-port-git-commit-"));
  await mkdir(join(workspace, ".git", "refs", "heads"), { recursive: true });
  await writeFile(join(workspace, ".git", "HEAD"), "ref: refs/heads/main\n", "utf8");
  await writeFile(
    join(workspace, ".git", "refs", "heads", "main"),
    "aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa\n",
    "utf8",
  );
  await writeFile(
    join(workspace, ".git", "config"),
    '[remote "origin"]\n\turl = git@example.test:private/repo.git\n',
    "utf8",
  );
  await writeFile(join(workspace, "tracked.txt"), "changed", "utf8");
  await writeFile(join(workspace, "untracked.txt"), "local", "utf8");
  await writeGitIndex(join(workspace, ".git", "index"), [
    { path: "tracked.txt", size: 1, mtimeSeconds: 1 },
  ]);

  const { server, url } = await startTestServer({
    cwd: workspace,
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });

  try {
    const getResponse = await fetch(`${url}/api/git-commit-preflight`, {
      headers: apiHeaders(server),
    });
    assert.equal(getResponse.status, 405);

    const response = await fetch(`${url}/api/git-commit-preflight`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "default",
        message: "Sensitive commit subject\n\nPrivate body",
      }),
    });
    assert.equal(response.status, 200);
    const payload = await response.json();
    const serialized = JSON.stringify(payload);
    assert.equal(payload.ok, true);
    assert.equal(payload.action.type, "git-commit");
    assert.equal(payload.action.execution, "blocked");
    assert.equal(payload.action.wouldCreateCommit, false);
    assert.equal(payload.action.gitSubprocess, false);
    assert.equal(payload.action.objectWrites, false);
    assert.equal(payload.action.refWrites, false);
    assert.equal(payload.appServer.touched, false);
    assert.equal(payload.source.branch, "main");
    assert.equal(payload.source.commitShort, "aaaaaaaaaaaa");
    assert.equal(payload.message.charCount, 38);
    assert.equal(payload.message.lineCount, 3);
    assert.equal(payload.message.subjectCharCount, 24);
    assert.equal(payload.message.textReturned, false);
    assert.equal(payload.status.changedCount, 2);
    assert.equal(payload.status.stagedStateKnown, false);
    assertActionPreflight(payload, "git-commit", "default");
    assert.equal(payload.policy.gitSubprocess, false);
    assert.equal(payload.policy.objectWrites, false);
    assert.equal(payload.policy.refWrites, false);
    assert.equal(payload.policy.requiresIndexPolicy, true);
    assert.equal(payload.policy.requiresHookPolicy, true);
    assert.equal(payload.policy.requiresIdentityPolicy, true);
    assert.equal(payload.policy.implemented, false);
    assert.equal(probeCalled, false);
    for (const marker of [
      "Sensitive commit subject",
      "Private body",
      workspace,
      "git@example.test",
      "private/repo",
      "tracked.txt",
      "untracked.txt",
    ]) {
      assert.equal(serialized.includes(marker), false, `leaked ${marker}`);
    }

    const confirm = await fetch(`${url}/api/action-preflight-confirm`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "default",
        actionType: "git-commit",
        preflightToken: payload.preflight.token,
        message: "Sensitive commit subject\n\nPrivate body",
      }),
    });
    assert.equal(confirm.status, 200);
    const confirmPayload = await confirm.json();
    assertActionPreflightConfirmation(confirmPayload, "git-commit", "default");
    assert.equal(JSON.stringify(confirmPayload).includes(payload.preflight.token), false);
    assert.equal(JSON.stringify(confirmPayload).includes("Sensitive commit subject"), false);
  } finally {
    await closeServer(server);
    await rm(workspace, { recursive: true, force: true });
  }
});

