    assert.equal(cancelPayload.result.loginRefReturned, false);
    assert.equal(cancelPayload.result.loginIdReturned, false);
    assert.equal(cancelPayload.probes.accountLoginCancel.loginIdReturned, false);
    assert.equal(cancelPayload.probes.accountLoginCancel.tokensReturned, false);
    assert.equal(cancelPayload.policy.loginRefsReturned, false);
    assert.equal(cancelPayload.policy.loginIdsReturned, false);
    assert.equal(cancelPayload.policy.authFlowCancel, true);
    assert.equal(cancelPayload.policy.auditLogWritten, true);
    assert.equal(cancelCalls.length, 1);
