    assert.equal(cancelHistoryItem.action.method, "account/login/cancel");
    assert.equal(cancelHistoryItem.action.authFlowCanceled, true);
    assert.equal(cancelHistoryItem.result.canceled, true);
    assert.equal(cancelHistoryItem.result.loginRefReturned, false);
    assert.equal(cancelHistoryItem.result.loginIdReturned, false);
