    assert.equal(auditRecords[1].event, "account-login-cancel-recorded");
    assert.equal(auditRecords[1].action.type, "account-login-cancel");
    assert.equal(auditRecords[1].action.method, "account/login/cancel");
    assert.equal(auditRecords[1].target.loginRefReturned, false);
    assert.equal(auditRecords[1].target.loginIdReturned, false);
