test("dev server blocks turn-start before app-server execution", async () => {
  let probeCalled = false;
  const { server, url } = await startTestServer({
    cwd: "/tmp/default-workspace",
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });

  try {
    const getResponse = await fetch(`${url}/api/turn-start`, {
      headers: apiHeaders(server),
    });
    assert.equal(getResponse.status, 405);

    const response = await fetch(`${url}/api/turn-start`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "default",
        thread: "b0153f06",
        prompt: "Sensitive user prompt\nmust never be echoed",
      }),
    });
    assert.equal(response.status, 403);
    const payload = await response.json();
    const serialized = JSON.stringify(payload);
    assert.equal(payload.ok, false);
    assert.equal(payload.action.type, "turn-start");
    assert.equal(payload.action.execution, "blocked");
    assert.equal(payload.action.modelTraffic, false);
    assert.equal(payload.action.sendsPromptToAppServer, false);
    assert.equal(payload.action.wouldStartTurn, false);
    assert.equal(payload.action.appServerTouched, false);
    assert.equal(payload.target.threadIdSuffix, "b0153f06");
    assert.equal(payload.prompt.charCount, 42);
    assert.equal(payload.prompt.lineCount, 2);
    assert.equal(payload.policy.requiresApprovalPipeline, true);
    assert.equal(payload.policy.implemented, false);
    assert.equal(probeCalled, false);
    assert.equal(serialized.includes("Sensitive"), false);
    assert.equal(serialized.includes("must never be echoed"), false);
    assert.equal(serialized.includes("/tmp/default-workspace"), false);

    const invalid = await fetch(`${url}/api/turn-start`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        thread: "../secret",
        prompt: "Sensitive invalid start prompt",
      }),
    });
    assert.equal(invalid.status, 400);
    assert.equal((await invalid.text()).includes("Sensitive invalid start prompt"), false);
    assert.equal(probeCalled, false);
  } finally {
    await closeServer(server);
  }
});

