test("dev server refuses live-session control before mutation when action audit log is unavailable", async () => {
  const calls = [];
  const { server, url } = await startTestServer({
    cwd: "/tmp/default-workspace",
    liveSessionControlEnabled: true,
    actionAuditLog: {
      persistent: true,
      ensureWritable() {
        throw new Error("unsafe /tmp/default-workspace/actions.jsonl");
      },
      append() {
        throw new Error("append should not run");
      },
    },
    liveSessionControlFn: async (options) => {
      calls.push(options);
      return { ok: true };
    },
  });

  try {
    const preflight = await fetch(`${url}/api/live-session-control-preflight`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "default",
        action: "interrupt",
        thread: "abcd1234",
        turn: "turn5678",
      }),
    });
    assert.equal(preflight.status, 200);
    const preflightPayload = await preflight.json();

    const response = await fetch(`${url}/api/live-session-control`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "default",
        action: "interrupt",
        thread: "abcd1234",
        turn: "turn5678",
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    assert.equal(response.status, 500);
    const text = await response.text();
    assert.equal(text.includes("Action audit log is unavailable"), true);
    assert.equal(text.includes(preflightPayload.preflight.token), false);
    assert.equal(text.includes("/tmp/default-workspace"), false);
    assert.equal(text.includes("abcd1234"), false);
    assert.equal(calls.length, 0);
  } finally {
    await closeServer(server);
  }
});

test("dev server can route live-session inventory and control through session manager", async () => {
  const calls = [];
  const sessionManager = {
    async listLoadedSessions(options) {
      calls.push({ method: "listLoadedSessions", options });
      return {
        ok: true,
        generatedAt: "2026-05-16T00:00:00.000Z",
        transport: "stdio-jsonl",
        protocol: "json-rpc-2.0-without-jsonrpc-field",
        initialize: {
          platformFamily: "unix",
          platformOs: "linux",
        },
        probes: {
          loadedSessions: {
            count: 1,
            returnedThreadCount: 1,
            hasNextCursor: false,
            threadIdSuffixes: ["abcd1234"],
          },
        },
        notifications: {},
        sessionManager: {
          enabled: true,
          persistentClient: true,
        },
      };
    },
    async controlLiveSession(options) {
      calls.push({ method: "controlLiveSession", options });
      return {
        ok: true,
        generatedAt: "2026-05-16T00:00:00.000Z",
        transport: "stdio-jsonl",
        protocol: "json-rpc-2.0-without-jsonrpc-field",
        initialize: {
          platformFamily: "unix",
          platformOs: "linux",
        },
        probes: {
          liveSessionControl: {
            action: "interrupt",
            method: "turn/interrupt",
            threadIdSuffix: "abcd1234",
            turnIdSuffix: "turn5678",
            resultStatus: "interrupt-requested",
            loadedSessionCount: 1,
            methodsUsed: ["thread/loaded/list", "thread/read", "turn/interrupt"],
            fullIdsReturned: false,
            threadContentReturned: false,
          },
        },
        notifications: {},
        sessionManager: {
          enabled: true,
          persistentClient: true,
        },
      };
    },
    async closeAll() {
      calls.push({ method: "closeAll" });
    },
  };
  const { server, url } = await startTestServer({
    cwd: "/tmp/default-workspace",
    loadedSessionsEnabled: true,
    liveSessionControlEnabled: true,
    sessionManagerEnabled: true,
    sessionManager,
    loadedSessionsFn: async () => {
      throw new Error("loadedSessionsFn should not run when session manager is enabled");
    },
    liveSessionControlFn: async () => {
      throw new Error("liveSessionControlFn should not run when session manager is enabled");
    },
  });

  try {
    const inventory = await fetch(`${url}/api/live-sessions`, {
      headers: apiHeaders(server),
    });
    assert.equal(inventory.status, 200);
    const inventoryPayload = await inventory.json();
    assert.deepEqual(inventoryPayload.liveSessions.threadIdSuffixes, ["abcd1234"]);
    assert.equal(calls[0].method, "listLoadedSessions");
    assert.equal(calls[0].options.workspace.cwd, "/tmp/default-workspace");

    const preflight = await fetch(`${url}/api/live-session-control-preflight`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "default",
        action: "interrupt",
        thread: "abcd1234",
        turn: "turn5678",
      }),
    });
    assert.equal(preflight.status, 200);
    const preflightPayload = await preflight.json();

    const response = await fetch(`${url}/api/live-session-control`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "default",
        action: "interrupt",
        thread: "abcd1234",
        turn: "turn5678",
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    assert.equal(response.status, 200);
    const payload = await response.json();
    assert.equal(payload.action.method, "turn/interrupt");
    assert.equal(payload.result.status, "interrupt-requested");
    assert.equal(calls[1].method, "controlLiveSession");
    assert.equal(calls[1].options.workspace.cwd, "/tmp/default-workspace");
    assert.equal(calls[1].options.threadIdSuffix, "abcd1234");
    assert.equal(calls[1].options.turnIdSuffix, "turn5678");
    assert.equal(JSON.stringify(payload).includes(preflightPayload.preflight.token), false);
  } finally {
    await closeServer(server);
  }
  assert.equal(calls.some((call) => call.method === "closeAll"), true);
});

