test("dev server preflights MCP tool calls without invoking tools or echoing arguments", async () => {
  let probeCalled = false;
  const { server, url } = await startTestServer({
    cwd: "/tmp/default-workspace",
    workspaceInputs: ["/tmp/second-workspace"],
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });

  try {
    const getResponse = await fetch(`${url}/api/mcp-tool-preflight`, {
      headers: apiHeaders(server),
    });
    assert.equal(getResponse.status, 405);

    const args = JSON.stringify({
      path: "/tmp/second-workspace/secret.txt",
      token: "sk-proj-privatevalue",
    });
    const response = await fetch(`${url}/api/mcp-tool-preflight`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "workspace-2",
        server: "private-mcp-server",
        tool: "private-tool",
        arguments: args,
      }),
    });
    assert.equal(response.status, 200);
    const payload = await response.json();
    const serialized = JSON.stringify(payload);
    assert.equal(payload.ok, true);
    assert.deepEqual(payload.workspace, {
      id: "workspace-2",
      label: "second-workspace",
      isDefault: false,
    });
    assert.equal(payload.appServer.touched, false);
    assert.equal(payload.appServer.modelTraffic, false);
    assert.equal(payload.appServer.toolTraffic, false);
    assert.equal(payload.action.type, "mcp-tool-preflight");
    assert.equal(payload.action.method, "mcpServer/tool/call");
    assert.equal(payload.action.execution, "blocked");
    assert.equal(payload.action.wouldInvokeTool, false);
    assertActionPreflight(payload, "mcp-tool-preflight", "workspace-2");
    assert.equal(payload.thread.present, false);
    assert.equal(payload.thread.threadIdSuffix, null);
    assert.equal(payload.thread.fullIdsReturned, false);
    assert.equal(payload.server.charCount, 18);
    assert.equal(payload.server.nameReturned, false);
    assert.equal(payload.tool.charCount, 12);
    assert.equal(payload.tool.nameReturned, false);
    assert.equal(payload.arguments.present, true);
    assert.equal(payload.arguments.charCount, args.length);
    assert.equal(payload.arguments.validJsonObject, true);
    assert.equal(payload.arguments.topLevelKeyCount, 2);
    assert.equal(payload.arguments.textReturned, false);
    assert.equal(payload.policy.toolInvocation, false);
    assert.equal(payload.policy.toolInvocationEnabled, false);
    assert.equal(payload.policy.executionRouteImplemented, true);
    assert.equal(payload.policy.executionGateEnabled, false);
    assert.equal(payload.policy.allowlistRequired, true);
    assert.equal(payload.policy.threadRequired, true);
    assert.equal(payload.policy.argumentTextReturned, false);
    assert.equal(payload.policy.namesReturned, false);
    assert.equal(payload.policy.implemented, true);
    assert.equal(probeCalled, false);
    for (const marker of [
      "private-mcp-server",
      "private-tool",
      "/tmp/second-workspace",
      "secret.txt",
      "sk-proj-privatevalue",
      "\"path\"",
      "codexHome",
      "userAgent",
    ]) {
      assert.equal(serialized.includes(marker), false, `leaked ${marker}`);
    }

    const historyResponse = await fetch(`${url}/api/settings-integrations?workspace=workspace-2`, {
      headers: apiHeaders(server),
    });
    assert.equal(historyResponse.status, 200);
    const historyPayload = await historyResponse.json();
    const historySerialized = JSON.stringify(historyPayload.preflightHistory);
    assert.equal(historyPayload.preflightHistory.count, 1);
    assert.equal(historyPayload.preflightHistory.preflightTokensReturned, false);
    assert.equal(historyPayload.preflightHistory.namesReturned, false);
    assert.equal(historyPayload.preflightHistory.argumentTextReturned, false);
    assert.equal(historyPayload.policy.preflightHistoryReturned, true);
    assert.equal(historyPayload.policy.preflightTokensReturned, false);
    const historyItem = historyPayload.preflightHistory.items[0];
    assert.equal(historyItem.action.type, "mcp-tool-preflight");
    assert.equal(historyItem.action.method, "mcpServer/tool/call");
    assert.equal(historyItem.action.wouldInvokeTool, false);
    assert.equal(historyItem.mcpTool.serverCharCount, 18);
    assert.equal(historyItem.mcpTool.toolCharCount, 12);
    assert.equal(historyItem.mcpTool.argumentTopLevelKeyCount, 2);
    assert.equal(historyItem.mcpTool.namesReturned, false);
    assert.equal(historyItem.mcpTool.argumentTextReturned, false);
    assert.equal(historyItem.preflight.tokenIssued, true);
    assert.equal(historyItem.preflight.tokenReturned, false);
    assert.equal(historyItem.policy.preflightTokenReturned, false);
    assert.equal(historyItem.policy.toolInvocation, false);
    for (const marker of [
      "private-mcp-server",
      "private-tool",
      "/tmp/second-workspace",
      "secret.txt",
      "sk-proj-privatevalue",
      "\"path\"",
      payload.preflight.token,
    ]) {
      assert.equal(historySerialized.includes(marker), false, `history leaked ${marker}`);
    }

    const invalid = await fetch(`${url}/api/mcp-tool-preflight`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        server: "   ",
        tool: "private-tool",
        arguments: "Sensitive invalid args",
      }),
    });
    assert.equal(invalid.status, 400);
    const invalidText = await invalid.text();
    assert.equal(invalidText.includes("private-tool"), false);
    assert.equal(invalidText.includes("Sensitive invalid args"), false);

    const rejected = await fetch(`${url}/api/mcp-tool-preflight`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "/tmp/second-workspace",
        server: "private-mcp-server",
        tool: "private-tool",
      }),
    });
    assert.equal(rejected.status, 404);
    assert.equal((await rejected.text()).includes("private-mcp-server"), false);
    assert.equal(probeCalled, false);
  } finally {
    await closeServer(server);
  }
});

