test("dev server preflights MCP resource reads without reading resources", async () => {
  let probeCalled = false;
  const { server, url } = await startTestServer({
    cwd: "/tmp/default-workspace",
    workspaceInputs: ["/tmp/second-workspace"],
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });

  try {
    const getResponse = await fetch(`${url}/api/mcp-resource-preflight`, {
      headers: apiHeaders(server),
    });
    assert.equal(getResponse.status, 405);

    const resource = "file:///tmp/second-workspace/secret.txt?token=sk-proj-privatevalue";
    const response = await fetch(`${url}/api/mcp-resource-preflight`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "workspace-2",
        server: "private-mcp-server",
        resource,
      }),
    });
    assert.equal(response.status, 200);
    const payload = await response.json();
    const serialized = JSON.stringify(payload);
    assert.equal(payload.ok, true);
    assert.deepEqual(payload.workspace, {
      id: "workspace-2",
      label: "second-workspace",
      isDefault: false,
    });
    assert.equal(payload.appServer.touched, false);
    assert.equal(payload.appServer.resourceTraffic, false);
    assert.equal(payload.action.type, "mcp-resource-preflight");
    assert.equal(payload.action.method, "mcpServer/resource/read");
    assert.equal(payload.action.execution, "blocked");
    assert.equal(payload.action.wouldReadResource, false);
    assertActionPreflight(payload, "mcp-resource-preflight", "workspace-2");
    assert.equal(payload.server.charCount, 18);
    assert.equal(payload.server.nameReturned, false);
    assert.equal(payload.resource.charCount, resource.length);
    assert.equal(payload.resource.uriReturned, false);
    assert.equal(payload.resource.contentReturned, false);
    assert.equal(payload.policy.resourceRead, false);
    assert.equal(payload.policy.resourceReadEnabled, false);
    assert.equal(payload.policy.executionRouteImplemented, true);
    assert.equal(payload.policy.executionGateEnabled, false);
    assert.equal(payload.policy.resourceContentReturned, false);
    assert.equal(payload.policy.resourceUrisReturned, false);
    assert.equal(payload.policy.namesReturned, false);
    assert.equal(payload.policy.implemented, true);
    assert.equal(probeCalled, false);
    for (const marker of [
      "private-mcp-server",
      "/tmp/second-workspace",
      "secret.txt",
      "sk-proj-privatevalue",
      "file://",
      "token=",
      "codexHome",
      "userAgent",
    ]) {
      assert.equal(serialized.includes(marker), false, `leaked ${marker}`);
    }

    const historyResponse = await fetch(`${url}/api/settings-integrations?workspace=workspace-2`, {
      headers: apiHeaders(server),
    });
    assert.equal(historyResponse.status, 200);
    const historyPayload = await historyResponse.json();
    const historySerialized = JSON.stringify(historyPayload.preflightHistory);
    assert.equal(historyPayload.preflightHistory.count, 1);
    assert.equal(historyPayload.preflightHistory.resourceReadEnabled, false);
    const historyItem = historyPayload.preflightHistory.items[0];
    assert.equal(historyItem.action.type, "mcp-resource-preflight");
    assert.equal(historyItem.action.method, "mcpServer/resource/read");
    assert.equal(historyItem.action.wouldReadResource, false);
    assert.equal(historyItem.mcpResource.serverCharCount, 18);
    assert.equal(historyItem.mcpResource.resourceCharCount, resource.length);
    assert.equal(historyItem.mcpResource.resourceUriReturned, false);
    assert.equal(historyItem.mcpResource.resourceContentReturned, false);
    assert.equal(historyItem.policy.resourceRead, false);
    assert.equal(historyItem.policy.preflightTokenReturned, false);
    for (const marker of [
      "private-mcp-server",
      "/tmp/second-workspace",
      "secret.txt",
      "sk-proj-privatevalue",
      "file://",
      "token=",
      payload.preflight.token,
    ]) {
      assert.equal(historySerialized.includes(marker), false, `history leaked ${marker}`);
    }

    const invalid = await fetch(`${url}/api/mcp-resource-preflight`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        server: "private-mcp-server",
        resource: "   ",
      }),
    });
    assert.equal(invalid.status, 400);
    const invalidText = await invalid.text();
    assert.equal(invalidText.includes("private-mcp-server"), false);
  } finally {
    await closeServer(server);
  }
});

