test("dev server preflights terminal commands without executing or echoing them", async () => {
  let probeCalled = false;
  const { server, url } = await startTestServer({
    cwd: "/tmp/default-workspace",
    workspaceInputs: ["/tmp/second-workspace"],
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });

  try {
    const getResponse = await fetch(`${url}/api/terminal-command-preflight`, {
      headers: apiHeaders(server),
    });
    assert.equal(getResponse.status, 405);

    const response = await fetch(`${url}/api/terminal-command-preflight`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "workspace-2",
        command: "cat /tmp/second-workspace/secret.txt\nrm -rf /tmp/private",
      }),
    });
    assert.equal(response.status, 200);
    const payload = await response.json();
    const serialized = JSON.stringify(payload);
    assert.equal(payload.ok, true);
    assert.deepEqual(payload.workspace, {
      id: "workspace-2",
      label: "second-workspace",
      isDefault: false,
    });
    assert.equal(payload.appServer.touched, false);
    assert.equal(payload.appServer.modelTraffic, false);
    assert.equal(payload.appServer.commandTraffic, false);
    assert.equal(payload.action.type, "terminal-command-preflight");
    assert.equal(payload.action.execution, "blocked");
    assert.equal(payload.action.wouldExecuteCommand, false);
    assert.equal(payload.action.commandExecution, false);
    assert.equal(payload.action.terminalSessionCreated, false);
    assertActionPreflight(payload, "terminal-command-preflight", "workspace-2");
    assert.equal(payload.command.charCount, 56);
    assert.equal(payload.command.lineCount, 2);
    assert.equal(payload.command.textReturned, false);
    assert.equal(payload.policy.commandExecution, false);
    assert.equal(payload.policy.terminalWrite, false);
    assert.equal(payload.policy.filesystemWrites, false);
    assert.equal(payload.policy.requiresApprovalPipeline, true);
    assert.equal(payload.policy.requiresLiveSessionManager, true);
    assert.equal(payload.policy.implemented, false);
    assert.equal(probeCalled, false);
    for (const marker of [
      "cat ",
      "rm -rf",
      "secret.txt",
      "/tmp/second-workspace",
      "/tmp/private",
      "codexHome",
      "userAgent",
    ]) {
      assert.equal(serialized.includes(marker), false, `leaked ${marker}`);
    }

    const mismatch = await fetch(`${url}/api/action-preflight-confirm`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "workspace-2",
        actionType: "terminal-command-preflight",
        preflightToken: payload.preflight.token,
        command: "cat /tmp/second-workspace/other-secret.txt",
      }),
    });
    assert.equal(mismatch.status, 403);
    assert.equal((await mismatch.text()).includes("other-secret.txt"), false);

    const confirm = await fetch(`${url}/api/action-preflight-confirm`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "workspace-2",
        actionType: "terminal-command-preflight",
        preflightToken: payload.preflight.token,
        command: "cat /tmp/second-workspace/secret.txt\nrm -rf /tmp/private",
      }),
    });
    assert.equal(confirm.status, 200);
    const confirmPayload = await confirm.json();
    assertActionPreflightConfirmation(confirmPayload, "terminal-command-preflight", "workspace-2");
    assert.equal(JSON.stringify(confirmPayload).includes(payload.preflight.token), false);
    assert.equal(JSON.stringify(confirmPayload).includes("secret.txt"), false);

    const replay = await fetch(`${url}/api/action-preflight-confirm`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "workspace-2",
        actionType: "terminal-command-preflight",
        preflightToken: payload.preflight.token,
        command: "cat /tmp/second-workspace/secret.txt\nrm -rf /tmp/private",
      }),
    });
    assert.equal(replay.status, 409);
    assert.equal((await replay.text()).includes("secret.txt"), false);

    const invalid = await fetch(`${url}/api/terminal-command-preflight`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        command: "   ",
      }),
    });
    assert.equal(invalid.status, 400);

    const rejected = await fetch(`${url}/api/terminal-command-preflight`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "/tmp/second-workspace",
        command: "echo secret",
      }),
    });
    assert.equal(rejected.status, 404);
    assert.equal((await rejected.text()).includes("echo secret"), false);
    assert.equal(probeCalled, false);
  } finally {
    await closeServer(server);
  }
});

