test("dev server executes command/exec terminal controls only behind opt-in and preflight token", async () => {
  const calls = [];
  const actionAuditDir = await mkdtemp(join(tmpdir(), "codex-terminal-control-action-audit-"));
  const actionAuditLogPath = join(actionAuditDir, "actions.jsonl");
  const sessionManager = {
    async controlTerminalSession(options) {
      calls.push(options);
      return {
        ok: true,
        generatedAt: "2026-05-16T00:00:00.000Z",
        transport: "stdio-jsonl",
        protocol: "json-rpc-2.0-without-jsonrpc-field",
        initialize: {
          platformFamily: "unix",
          platformOs: "linux",
          codexHome: "/tmp/private-home",
          userAgent: "mock/0.0.0",
        },
        probes: {
          terminalControl: {
            terminalAction: options.terminalAction,
            method: options.method,
            resultStatus: "completed",
            sessionSelectorCharCount: options.session.length,
            inputCharCount: options.input?.length ?? 0,
            inputLineCount: options.input ? options.input.split(/\r\n|\r|\n/).length : 0,
            rows: Number.parseInt(options.rows ?? "0", 10) || null,
            cols: Number.parseInt(options.cols ?? "0", 10) || null,
            methodsUsed: [options.method],
            sessionIdentifier: "process-private-id",
            output: "Sensitive terminal output",
          },
        },
        notifications: {
          "command/exec/outputDelta": 1,
        },
      };
    },
    async closeAll() {},
  };
  const { server, url } = await startTestServer({
    cwd: "/tmp/default-workspace",
    terminalControlEnabled: true,
    sessionManagerEnabled: true,
    sessionManager,
    actionAuditLog: createActionAuditLog({
      path: actionAuditLogPath,
      now: () => "2026-05-16T00:00:00.000Z",
    }),
  });

  try {
    const statusResponse = await fetch(`${url}/api/terminal-actions?workspace=default`, {
      headers: apiHeaders(server),
    });
    assert.equal(statusResponse.status, 200);
    const statusPayload = await statusResponse.json();
    assert.equal(statusPayload.terminal.writeEnabled, true);
    assert.equal(statusPayload.terminal.resizeEnabled, true);
    assert.equal(statusPayload.terminal.terminateEnabled, true);
    assert.equal(statusPayload.actions.terminalControlEnabled, true);
    assert.equal(statusPayload.actionScope.terminalInputEnabled, true);
    assert.equal(statusPayload.actionScope.processSpawnEnabled, false);
    assert.deepEqual(statusPayload.actionScope.blockedHighRiskMethods, [
      "process/spawn",
      "process/writeStdin",
      "process/resizePty",
      "process/kill",
      "thread/shellCommand",
      "thread/backgroundTerminals/list",
      "thread/backgroundTerminals/terminate",
    ]);
    assert.equal(statusPayload.policy.commandExecTerminalControl, true);
    assert.equal(statusPayload.policy.terminalWrite, true);
    assert.equal(JSON.stringify(statusPayload).includes("/tmp/default-workspace"), false);

    const processPreflight = await fetch(`${url}/api/terminal-control-preflight`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "default",
        action: "write",
        method: "process/writeStdin",
        session: "processSession1234",
        input: "Sensitive terminal input",
      }),
    });
    assert.equal(processPreflight.status, 200);
    const processPreflightPayload = await processPreflight.json();
    assert.equal(processPreflightPayload.policy.executionGateEnabled, false);
    assert.equal(processPreflightPayload.policy.processControlBlocked, true);
    const processRun = await fetch(`${url}/api/terminal-control`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "default",
        action: "write",
        method: "process/writeStdin",
        session: "processSession1234",
        input: "Sensitive terminal input",
        preflightToken: processPreflightPayload.preflight.token,
      }),
    });
    assert.equal(processRun.status, 403);
    assert.equal((await processRun.text()).includes("processSession1234"), false);
    assert.equal(calls.length, 0);

    const input = "Sensitive terminal input";
    const preflight = await fetch(`${url}/api/terminal-control-preflight`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "default",
        action: "write",
        method: "command/exec/write",
        session: "commandSession1234",
        input,
      }),
    });
    assert.equal(preflight.status, 200);
    const preflightPayload = await preflight.json();
    assert.equal(preflightPayload.policy.executionGateEnabled, true);
    assert.equal(preflightPayload.policy.processControlBlocked, false);
    assertActionPreflight(preflightPayload, "terminal-control-preflight", "default");

    const missingPreflight = await fetch(`${url}/api/terminal-control`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "default",
        action: "write",
        method: "command/exec/write",
        session: "commandSession1234",
        input,
      }),
    });
    assert.equal(missingPreflight.status, 400);
    assert.equal((await missingPreflight.text()).includes("commandSession1234"), false);
    assert.equal(calls.length, 0);

    const response = await fetch(`${url}/api/terminal-control`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "default",
        action: "write",
        method: "command/exec/write",
        session: "commandSession1234",
        input,
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    assert.equal(response.status, 200);
    const payload = await response.json();
    const serialized = JSON.stringify(payload);
    assert.equal(payload.ok, true);
    assert.equal(payload.appServer.touched, true);
    assert.equal(payload.appServer.modelTraffic, false);
    assert.deepEqual(payload.appServer.auditedMethods, ["command/exec/write"]);
    assert.equal(payload.action.type, "terminal-control");
    assert.equal(payload.action.terminalAction, "write");
    assert.equal(payload.action.method, "command/exec/write");
    assert.equal(payload.action.terminalWrite, true);
    assert.equal(payload.action.terminalSessionTouched, true);
    assert.equal(payload.preflight.tokenConsumed, true);
    assert.equal(payload.preflight.tokenReturned, false);
    assert.equal(payload.target.sessionSelectorCharCount, "commandSession1234".length);
    assert.equal(payload.target.sessionIdentifierReturned, false);
    assert.equal(payload.terminalControl.input.charCount, input.length);
    assert.equal(payload.terminalControl.input.textReturned, false);
    assert.equal(payload.result.status, "completed");
    assert.equal(payload.result.outputTextReturned, false);
    assert.equal(payload.result.terminalSessionIdentifiersReturned, false);
    assert.equal(payload.policy.terminalWrite, true);
    assert.equal(payload.policy.inputTextReturned, false);
    assert.equal(payload.policy.terminalOutputReturned, false);
    assert.equal(payload.policy.terminalSessionIdentifiersReturned, false);
    assert.equal(payload.policy.auditLogPersistent, true);
    assert.equal(payload.policy.auditLogWritableChecked, true);
    assert.equal(payload.policy.auditLogWritten, true);
    assert.equal(payload.notifications["command/exec/outputDelta"], 1);
    assert.equal(calls.length, 1);
    assert.equal(calls[0].workspace.cwd, "/tmp/default-workspace");
    assert.equal(calls[0].terminalAction, "write");
    assert.equal(calls[0].method, "command/exec/write");
    assert.equal(calls[0].session, "commandSession1234");
    assert.equal(calls[0].input, input);
    for (const marker of [
      preflightPayload.preflight.token,
      "commandSession1234",
      "process-private-id",
      "Sensitive terminal input",
      "Sensitive terminal output",
      "/tmp/default-workspace",
      "/tmp/private-home",
      "codexHome",
      "userAgent",
    ]) {
      assert.equal(serialized.includes(marker), false, `leaked ${marker}`);
    }

    const replay = await fetch(`${url}/api/terminal-control`, {
      method: "POST",
      headers: jsonHeaders(server),
      body: JSON.stringify({
        workspace: "default",
        action: "write",
        method: "command/exec/write",
        session: "commandSession1234",
        input,
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    assert.equal(replay.status, 409);
    assert.equal(calls.length, 1);

    const auditRecords = (await readFile(actionAuditLogPath, "utf8"))
      .trim()
      .split("\n")
      .map((line) => JSON.parse(line));
    assert.equal(auditRecords.length, 1);
    assert.equal(auditRecords[0].event, "terminal-control-recorded");
    assert.equal(auditRecords[0].action.type, "terminal-control");
    assert.equal(auditRecords[0].action.terminalAction, "write");
    assert.equal(auditRecords[0].target.sessionSelectorCharCount, "commandSession1234".length);
    assert.equal(auditRecords[0].target.sessionIdentifierReturned, false);
    assert.equal(auditRecords[0].result.outputTextReturned, false);
    assert.equal(auditRecords[0].policy.sensitivePayloadLogged, false);
    const auditSerialized = JSON.stringify(auditRecords);
    for (const marker of [
      preflightPayload.preflight.token,
      "commandSession1234",
      "process-private-id",
      "Sensitive terminal input",
      "Sensitive terminal output",
      "/tmp/default-workspace",
      "/tmp/private-home",
      "codexHome",
      "userAgent",
    ]) {
      assert.equal(auditSerialized.includes(marker), false, `audit leaked ${marker}`);
    }
  } finally {
    await closeServer(server);
    await rm(actionAuditDir, { recursive: true, force: true });
  }
});

