    assert.equal(statusResponse.status, 200);
    const statusPayload = await statusResponse.json();
    assert.equal(statusPayload.terminal.backgroundListEnabled, true);
    assert.equal(statusPayload.terminal.backgroundTerminateEnabled, true);
    assert.equal(statusPayload.actions.terminalBackgroundListEnabled, true);
    assert.equal(statusPayload.actions.terminalBackgroundTerminateEnabled, true);
